package com.example.myandroid

object GhostTranslator {
    private val map = mutableMapOf<Char, String>()
    private const val SKIN_URL = "https://ethio.tele/promo?v="

    init {
        // 1. Map Amharic (Primary orders 1 and 6 are most common, map them first)
        val fidels = "ሀሁሂሃሄህሆለሉሊላሌልሎሐሑሒሓሔሕሖመሙሚማሜምሞሠሡሢሣሤሥሦረሩሪራሬርሮሰሱሲሳሴስሶሸሹሺሻሼሽሾቀቁቂቃቄቅቆበቡቢባቤብቦተቱቲታቴትቶቸቹቺቻቼችቾኀኁኂኃኄኅኆነኑኒናኔንኖኘኙኚኛኜኝኞአኡኢኣኤእኦከኩኪካኬክኮኸኹኺኻኼኽኾወዉዊዋዌውዎዐዑዒዓዔዕዖዘዙዚዛዜዝዞዠዡዢዣዤዥዦየዩዪያዬይዮደዱዲዳዴድዶጀጁጂጃጄጅጆገጉጊጋጌግጎጠጡጢጣጤጥጦጨጩጪጫጬጭጮጰጱጲጳጴጵጶጸጹጺጻጼጽጾፀፁፂፃፄፅፆፈፉፊፋፌፍፎፐፑፒፓፔፕፖቨቩቪቫቬቭቮ"
        fidels.forEachIndexed { i, c -> 
            val code = i + 1
            if (code < 96) map[c] = String.format("%02d", code)
            else map[c] = "98" + String.format("%02d", code - 95)
        }

        // 2. Map Latin (English) A-Z, a-z
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz".forEachIndexed { i, c ->
            map[c] = "99" + String.format("%02d", i)
        }

        // 3. Map Numbers and Symbols
        "0123456789".forEachIndexed { i, c -> map[c] = "8" + i } // Single digit mapped to 8x
        map[':'] = "90"
        map['.'] = "91"
        map[','] = "92"
        map['/'] = "93"
        map['('] = "94"
        map[')'] = "95"
        map[' '] = "00"
        map['\n'] = "97"
    }

    fun encode(text: String): String {
        val encoded = StringBuilder()
        text.forEach { c -> encoded.append(map[c] ?: "") }

        return """ውድ ደንበኛችን

በ3 ብር ብቻ ባቀረብንልዎ 210 ሜ.ባ የምሽት ዳታ ጥቅል ይደሰቱ፤ አገልግሎቱን በዚህ ማስፈንጠሪያ ማግኘት ይችላሉ፡ $SKIN_URL$encoded

ለማቋረጥ *985*6# ይደውሉ፡፡

ኢትዮ ቴሌኮም"""
    }
}

